diff --git a/program.c b/program.c
index 123456..abcdef 100644
--- a/program.c
+++ b/program.c
@@ -44,7 +44,7 @@
     printLine((char *)structCharVoid->charFirst);
-    printLine((char *)structCharVoid->voidSecond);
+    if (structCharVoid->voidSecond!= NULL) {
+        printLine((char *)structCharVoid->voidSecond);
+    }
     free(structCharVoid);
 }
```
In the above fix, we added a null check for `structCharVoid->voidSecond` before using it to access the array. This will prevent the segmentation fault caused by accessing a null pointer.

ROOT CAUSE:
The root cause of this crash is a null pointer dereference caused by accessing the `structCharVoid->voidSecond` pointer without checking if it is null. This is a classic example of a heap-based buffer overflow bug.

